mapper.sql:
WHERE 1 = 1
AND B.CO_ID = #{coId}

    AND (B.BIZ_NM LIKE CONCAT('%', #{searchKeyword}, '%')
      OR B.BIZ_CD LIKE CONCAT('%', #{searchKeyword}, '%')
      OR B.ORDPL_NM LIKE CONCAT('%', #{searchKeyword}, '%'))

AND B.BIZ_STTS_CD = #{searchBizSttsCd}
AND B.INST_SE_CD = #{searchInstSeCd}
AND B.BIZ_KND_CD = #{searchBizKndCd}
AND B.BIZ_SE_CD = #{searchBizSeCd}
AND B.OTST_YMD >= #{sDate}
AND B.BIZ_END_YMD <= #{eDate}

mapper.select:
SELECT B.BIZ_ID, B.CO_ID, B.BIZ_CD, B.BIZ_NM, B.INST_SE_CD, B.BIZ_KND_CD, B.BIZ_SE_CD, B.ORDPL_NM ,DATE_FORMAT(B.CTRT_YMD, '%Y-%m-%d') AS CTRT_YMD ,DATE_FORMAT(B.OTST_YMD, '%Y-%m-%d') AS OTST_YMD ,DATE_FORMAT(IFNULL(B.BIZ_BGNG_YMD, B.OTST_YMD), '%Y-%m-%d') AS BIZ_BGNG_YMD ,DATE_FORMAT(B.BIZ_END_YMD, '%Y-%m-%d') AS BIZ_END_YMD ,B.CTRT_AMT, B.GIVE_MTHD_CD, B.GIVE_MTHD_CN ,DATE_FORMAT(B.GIVE_DDT_YMD, '%Y-%m-%d') AS GIVE_DDT_YMD ,DATE_FORMAT(B.DFRP_GRNTE_BGNG_YMD, '%Y-%m-%d') AS DFRP_GRNTE_BGNG_YMD ,DATE_FORMAT(B.DFRP_GRNTE_END_YMD, '%Y-%m-%d') AS DFRP_GRNTE_END_YMD ,B.RMRK_CN, B.BIZ_STTS_CD ,DATE_FORMAT(B.REG_DT, '%Y-%m-%d %H:%i:%s') AS REG_DT
FROM biz_info B
WHERE B.BIZ_ID = #{bizId}

mapper.insert:
INSERT INTO biz_info (
     BIZ_ID, CO_ID, BIZ_CD, BIZ_NM, INST_SE_CD, BIZ_KND_CD, BIZ_SE_CD, ORDPL_NM
    ,CTRT_YMD, OTST_YMD, BIZ_BGNG_YMD, BIZ_END_YMD, CTRT_AMT, GIVE_MTHD_CD, GIVE_MTHD_CN, GIVE_DDT_YMD
    ,DFRP_GRNTE_BGNG_YMD, DFRP_GRNTE_END_YMD, RMRK_CN, BIZ_STTS_CD, REG_DT
) VALUES (
     #{bizId}, #{coId}, #{bizCd}, #{bizNm}, #{instSeCd}, #{bizKndCd}, #{bizSeCd}, #{ordplNm}
    ,NULLIF(#{ctrtYmd}, ''), NULLIF(#{otstYmd}, ''), NULLIF(#{otstYmd}, ''), NULLIF(#{bizEndYmd}, '')
    ,#{ctrtAmt}, NULLIF(#{giveMthdCd}, ''), #{giveMthdCn}, NULLIF(#{giveDdtYmd}, '')
    ,NULLIF(#{dfrpGrnteBgngYmd}, ''), NULLIF(#{dfrpGrnteEndYmd}, ''), #{rmrkCn}
    ,COALESCE(NULLIF(#{bizSttsCd}, ''), (
        SELECT C.CD FROM cmn_cd C
        WHERE C.CD_GROUP_ID = 'BIZ_STTS_CD' AND C.USE_YN = 'Y' AND C.DFLT_YN = 'Y'
        ORDER BY C.SORT_SEQ ASC, C.CD ASC LIMIT 1
    )), NOW()
)

mapper.update:
UPDATE biz_info
SET
     BIZ_NM = #{bizNm}
    ,INST_SE_CD = #{instSeCd}
    ,BIZ_KND_CD = #{bizKndCd}
    ,BIZ_SE_CD = #{bizSeCd}
    ,ORDPL_NM = #{ordplNm}
    ,CTRT_YMD = NULLIF(#{ctrtYmd}, '')
    ,OTST_YMD = NULLIF(#{otstYmd}, '')
    ,BIZ_BGNG_YMD = NULLIF(#{otstYmd}, '')
    ,BIZ_END_YMD = NULLIF(#{bizEndYmd}, '')
    ,CTRT_AMT = #{ctrtAmt}
    ,GIVE_MTHD_CD = NULLIF(#{giveMthdCd}, '')
    ,GIVE_MTHD_CN = #{giveMthdCn}
    ,GIVE_DDT_YMD = NULLIF(#{giveDdtYmd}, '')
    ,DFRP_GRNTE_BGNG_YMD = NULLIF(#{dfrpGrnteBgngYmd}, '')
    ,DFRP_GRNTE_END_YMD = NULLIF(#{dfrpGrnteEndYmd}, '')
    ,RMRK_CN = #{rmrkCn}
    ,BIZ_STTS_CD = #{bizSttsCd}
WHERE BIZ_ID = #{bizId}

mapper.select:
SELECT C.CUST_SN, C.CO_ID, C.CUST_CO_NM, C.CUST_SE_CD, IFNULL(CUST_CD.CD_NM, C.CUST_SE_CD) AS CUST_SE_NM ,C.BRNO, C.RPRSV_NM, C.TELNO, C.ADDR, C.DADDR, C.USE_YN ,DATE_FORMAT(C.REG_DT, '%Y-%m-%d %H:%i:%s') AS REG_DT FROM cust_info C LEFT JOIN cmn_cd CUST_CD ON CUST_CD.CD_GROUP_ID = 'CUST_SE_CD' AND CUST_CD.CD = C.CUST_SE_CD AND CUST_CD.USE_YN = 'Y' WHERE C.USE_YN = 'Y' AND C.CO_ID = #{coId}
AND (C.CUST_CO_NM LIKE CONCAT('%', #{searchKeyword}, '%') OR C.BRNO LIKE CONCAT('%', #{searchKeyword}, '%'))
ORDER BY C.CUST_CO_NM ASC, C.CUST_SN DESC

SELECT C.*
FROM cust_info C
WHERE C.CUST_SN = #{custSn}

mapper.insert:
INSERT INTO cust_info (
     CO_ID, CUST_CO_NM, CUST_SE_CD, BRNO, RPRSV_NM, TELNO, ADDR, DADDR, USE_YN, RGTR_ID, REG_DT
) VALUES (
     #{coId}, #{custCoNm}, #{custSeCd}, #{brno}, #{rprsvNm}, #{telno}, #{addr}, #{daddr}, 'Y', #{rgtrId}, NOW()
)

mapper.update:
UPDATE cust_info
SET
     CUST_CO_NM = #{custCoNm}
    ,CUST_SE_CD = #{custSeCd}
    ,BRNO = #{brno}
    ,RPRSV_NM = #{rprsvNm}
    ,TELNO = #{telno}
    ,ADDR = #{addr}
    ,DADDR = #{daddr}
    ,MDFR_ID = #{mdfrId}
    ,MDFCN_DT = NOW()
WHERE CUST_SN = #{custSn}

mapper.insert:
INSERT INTO biz_cust_rel (
     BIZ_ID, CUST_SN, REL_SE_CD, REL_LVL, DIRECT_CTRT_YN, RMRK_CN, USE_YN, RGTR_ID, REG_DT
) VALUES (
     #{bizId}, #{custSn}, #{relSeCd}, #{relLvl}, COALESCE(NULLIF(#{directCtrtYn}, ''), 'N')
    ,#{rmrkCn}, 'Y', #{rgtrId}, NOW()
)

mapper.update:
UPDATE biz_cust_rel
SET
     CUST_SN = #{custSn}
    ,REL_SE_CD = #{relSeCd}
    ,REL_LVL = #{relLvl}
    ,DIRECT_CTRT_YN = COALESCE(NULLIF(#{directCtrtYn}, ''), 'N')
    ,RMRK_CN = #{rmrkCn}
    ,MDFR_ID = #{mdfrId}
    ,MDFCN_DT = NOW()
WHERE BIZ_CUST_REL_SN = #{bizCustRelSn}
  AND BIZ_ID = #{bizId}

UPDATE biz_cust_rel
SET USE_YN = 'N', MDFR_ID = #{mdfrId}, MDFCN_DT = NOW()
WHERE BIZ_CUST_REL_SN = #{bizCustRelSn}
  AND BIZ_ID = #{bizId}

