) VALUES (
     #{bizId}, NULLIF(#{userId}, ''), #{inputMnpwNm}, #{inputSeCd}, #{roleNm}, #{jbpsNm}
    ,NULLIF(#{inputBgngYmd}, ''), NULLIF(#{inputEndYmd}, ''), #{inputMcnt}, #{untprc}, #{rmrkCn}, 'Y', #{rgtrId}, NOW()
)

